130	/// Resolve a path that may be absolute or relative-to-project-root.
131	fn rbtdrp_resolve(root: &Path, raw: &str) -> PathBuf {
132	    if Path::new(raw).is_absolute() {
133	        PathBuf::from(raw)
134	    } else {
135	        root.join(raw)
136	    }
137	}
