400	/// Pick the next free moniker for `family_stem` by walking the depot_list
401	/// invocation's BURV output dir for `<family>NNNNNN.depot` files, parsing
402	/// the numeric suffix from each, and returning `<family><max + 1>`. Returns
403	/// `<family>RBTDRP_FAMILY_NUMERIC_FLOOR` when no matching files exist or the
404	/// output dir is missing (first run, no prior depots).
405	fn rbtdrp_pick_next_moniker(
406	    list_result: &crate::rbtdri_invocation::rbtdri_InvokeResult,
407	    family_stem: &str,
408	) -> Result<String, String> {
409	    let dir = list_result
410	        .burv_output
411	        .join(crate::rbtdri_invocation::RBTDRI_BURV_OUTPUT_SUBDIR);
412	
413	    let entries = match std::fs::read_dir(&dir) {
414	        Ok(e) => e,
415	        Err(_) => {
416	            return Ok(format!("{}{}", family_stem, RBTDRP_FAMILY_NUMERIC_FLOOR));
417	        }
418	    };
419	
420	    let suffix_ext = format!(".{}", RBTDRP_FACT_EXT_DEPOT);
421	    let mut max_suffix: Option<u32> = None;
422	    for entry in entries.flatten() {
423	        let name = match entry.file_name().into_string() {
424	            Ok(n) => n,
425	            Err(_) => continue,
426	        };
427	        let stem = match name.strip_suffix(&suffix_ext) {
428	            Some(s) => s,
429	            None => continue,
430	        };
431	        let numeric = match stem.strip_prefix(family_stem) {
432	            Some(s) => s,
433	            None => continue,
434	        };
435	        if numeric.len() != RBTDRP_FAMILY_NUMERIC_WIDTH {
436	            continue;
437	        }
438	        let parsed: u32 = match numeric.parse() {
439	            Ok(n) => n,
440	            Err(_) => continue,
441	        };
442	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
443	    }
444	
445	    let next = match max_suffix {
446	        Some(m) => m + 1,
447	        None => RBTDRP_FAMILY_NUMERIC_FLOOR,
448	    };
449	    Ok(format!("{}{}", family_stem, next))
450	}
