452	/// Compose the depot project_id from kindled regime values. Mirrors RBDC's
453	/// derivation: `${RBRR_CLOUD_PREFIX}d-${moniker}`. Used by cases 2 and 3 to
454	/// recover the project_id post-levy without re-reading a fact file (the
455	/// pre-collapse `rbgp_fact_depot_project_id` producer is gone).
456	fn rbtdrp_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
457	    let rbrr = root.join(RBTDRP_RBRR_FILE);
458	    let cloud_prefix = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX)
459	        .ok_or_else(|| format!("RBRR_CLOUD_PREFIX missing from {}", rbrr.display()))?;
460	    Ok(format!("{}d-{}", cloud_prefix, moniker))
461	}
462	
463	/// Set `RBRR_DEPOT_MONIKER` in rbrr.env to `moniker` and commit. Cases 2-3
464	/// use this to install a moniker that drives `RBDC_DEPOT_PROJECT_ID` via
465	/// kindle derivation. The commit is separate from the throwaway-prefix
466	/// commit so the audit trail shows the moniker landing as its own pace.
467	fn rbtdrp_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
468	    let rbrr = root.join(RBTDRP_RBRR_FILE);
469	    let content = std::fs::read_to_string(&rbrr)
470	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
471	    let new_content = rbtdrp_replace_env_fields(
472	        &content,
473	        &[(RBTDRP_FIELD_RBRR_DEPOT_MONIKER, moniker)],
474	    );
475	    std::fs::write(&rbrr, &new_content)
476	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
477	
478	    let commit_msg = format!(
479	        "pristine-lifecycle fixture: set {}={}",
480	        RBTDRP_FIELD_RBRR_DEPOT_MONIKER, moniker
481	    );
482	    rbtdrp_git_add_and_commit(root, RBTDRP_RBRR_FILE, &commit_msg)
483	}
