485	// ── Case ─────────────────────────────────────────────────────
486	
487	/// Case 1 — marshal-zero attestation. Aggregates all five violation classes
488	/// into a single diagnostic. A passing run is the proof that `rbw-MZ` was
489	/// just executed and committed.
490	fn rbtdrp_marshal_zero_attestation(_dir: &Path) -> rbtdre_Verdict {
491	    let root = match std::env::current_dir() {
492	        Ok(r) => r,
493	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot resolve project root: {}", e)),
494	    };
495	
496	    let rbrr = root.join(RBTDRP_RBRR_FILE);
497	    if !rbrr.exists() {
498	        return rbtdre_Verdict::Fail(format!("RBRR file not found: {}", rbrr.display()));
499	    }
500	
501	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR").unwrap_or_default();
