531	/// Wrapper invocation: call `rbtdri_invoke_global` and tee stdout/stderr to
532	/// `dir/<label>-stdout.txt` / `dir/<label>-stderr.txt` for diagnostic review.
533	/// Returns `Ok(InvokeResult)` regardless of exit code; callers decide what
534	/// counts as failure.
535	fn rbtdrp_invoke_logged(
536	    ctx: &mut rbtdri_Context,
537	    colophon: &str,
538	    args: &[&str],
539	    extra_env: &[(&str, &str)],
540	    dir: &Path,
541	    label: &str,
542	) -> Result<crate::rbtdri_invocation::rbtdri_InvokeResult, String> {
543	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
544	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
545	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
546	    Ok(result)
547	}
